const data = $input.first().json;
const atrasadas = data.atrasadas || 0;
const andamento = data.andamento || 0;
const revisao = data.revisao || 0;

let relatorio = `📊 *Resumo do CRM Maia*\n`;
relatorio += `🚨 Tarefas Atrasadas: ${atrasadas}\n`;
relatorio += `🔥 Em Andamento: ${andamento}\n`;
relatorio += `👀 Aguardando Revisão: ${revisao}\n\n`;

if(atrasadas > 0) {
  relatorio += `_Atenção: A equipe precisa agir rápido nas tarefas atrasadas!_`;
} else {
  relatorio += `_Parabéns: Tudo em dia!_`;
}

return [{ json: { text: relatorio, toolResponse: relatorio } }];
